const SymptomsHorizontal = () => {
  const sectionRef = useRef(null);
  const trackRef = useRef(null);

 useEffect(() => {
  const section = sectionRef.current;
  const track = trackRef.current;

  let ctx;

  const mm = gsap.matchMedia();

  mm.add("(min-width: 769px)", () => {
    ctx = gsap.context(() => {
      const getScrollAmount = () => {
        return -(track.scrollWidth - section.offsetWidth);
      };

      gsap.to(track, {
        x: getScrollAmount,
        ease: "none",
        scrollTrigger: {
          trigger: section,
          start: "top top",
          end: () => `+=${track.scrollWidth - section.offsetWidth}`,
          scrub: 1,
          pin: true,
          anticipatePin: 1,
          invalidateOnRefresh: true,
        },
      });
    }, section);
  });

  mm.add("(max-width: 768px)", () => {
    ctx = gsap.context(() => {
      const cards = gsap.utils.toArray(".symptom-card");
      let index = 0;

      gsap.set(track, { x: 0 });

      const autoplay = setInterval(() => {
        index = (index + 1) % cards.length;

        gsap.to(track, {
          x: -index * track.parentElement.offsetWidth,
          duration: 0.8,
          ease: "power2.inOut",
        });
      }, 2500);

      return () => clearInterval(autoplay);
    }, section);
  });

  return () => {
    mm.revert();
    if (ctx) ctx.revert();
  };
}, []);

  return (
    <section className="symptoms-horizontal-section" ref={sectionRef}>
      <div className="symptoms-heading-wrap">
        <h2>When The Spine Is Affected; Symptoms Appear</h2>
      </div>

      <div className="symptoms-scroll-area">
        <div className="symptoms-track" ref={trackRef}>
          {symptoms.map((item, index) => (
            <div className="symptom-card" key={index}>
              <div className="symptom-icon">
                <span>{item.icon}</span>
              </div>

              <h3>{item.title}</h3>
              <p>{item.text}</p>
            </div>
          ))}
        </div>
      </div>

      <div className="symptoms-bottom">
        <p>
          Understanding the underlying cause is the first step in choosing the
          right treatment
        </p>

        <a href="#contact" className="symptoms-btn">
          Book a consultation
        </a>
      </div>
    </section>
  );
};

export default SymptomsHorizontal;